messages.content:
{
  "children": [
    {
      "name": "IngestData",
      "purpose": "Read and parse input data from source, store raw data in raw_data store",
      "behavior": "Extract source from input, read data, parse into records, store in raw_data, return count and errors",
      "boundary": {
        "in_scope": [
          "reading source",
          "parsing data",
          "storing raw records"
        ],
        "out_of_scope": [
          "transformation",
          "validation",
          "export"
        ]
      },
      "semantic_inputs": [
        "input (parent input)"
      ],
      "semantic_outputs": [
        "ingest_result (count, errors)"
      ],
      "preconditions": [
        "input contains valid source"
      ],
      "postconditions": [
        "raw_data populated with records"
      ],
      "guarantees": [
        "logs each step",
        "returns count of ingested records"
      ],
      "composition_role": "transform",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "input",
          "type": "dict",
          "description": "JSON with action and source",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "ingest_result",
          "type": "dict",
          "description": "JSON with records_ingested (int) and errors (list)",
          "consumer": "parent"
        }
      ],
      "signature": "def IngestData(input: dict) -> dict"
    },
    {
      "name": "TransformData",
      "purpose": "Apply transformations to raw data and store in processed_data",
      "behavior": "Read raw_data, apply transformation rules (e.g., mapping, cleaning), write to processed_data, return count and errors",
      "boundary": {
        "in_scope": [
          "transformation logic",
          "data cleaning",
          "mapping"
        ],
        "out_of_scope": [
          "ingestion",
          "validation",
          "export"
        ]
      },
      "semantic_inputs": [
        "transform_config (from parent input)",
        "raw_data (from data store)"
      ],
      "semantic_outputs": [
        "transform_result (count, errors)"
      ],
      "preconditions": [
        "raw_data is populated"
      ],
      "postconditions": [
        "processed_data contains transformed records"
      ],
      "guarantees": [
        "logs each step",
        "returns count of transformed records"
      ],
      "composition_role": "transform",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "transform_config",
          "type": "dict",
          "description": "Transformation rules from parent input",
          "source": "parent input"
        },
        {
          "name": "raw_data",
          "type": "list",
          "description": "Records from raw_data store",
          "source": "internal leaf access (raw_data store)"
        }
      ],
      "outputs": [
        {
          "name": "transform_result",
          "type": "dict",
          "description": "JSON with records_transformed (int) and errors (list)",
          "consumer": "parent"
        }
      ],
      "signature": "def TransformData(transform_config: dict, raw_data: list) -> dict"
    },
    {
      "name": "ValidateQuality",
      "purpose": "Check quality of transformed data, mark invalid records",
      "behavior": "Read processed_data, apply validation rules (e.g., schema, range, completeness), mark invalid records, return validation summary",
      "boundary": {
        "in_scope": [
          "validation rules",
          "quality checks"
        ],
        "out_of_scope": [
          "transformation",
          "export"
        ]
      },
      "semantic_inputs": [
        "validation_rules (from parent input)",
        "processed_data (from data store)"
      ],
      "semantic_outputs": [
        "validation_result (valid_count, invalid_count, errors)"
      ],
      "preconditions": [
        "processed_data is populated"
      ],
      "postconditions": [
        "valid records are marked, invalid records are flagged"
      ],
      "guarantees": [
        "logs each step",
        "returns validation summary"
      ],
      "composition_role": "validate",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "validation_rules",
          "type": "dict",
          "description": "Rules for quality checks from parent input",
          "source": "parent input"
        },
        {
          "name": "processed_data",
          "type": "list",
          "description": "Transformed records from processed_data store",
          "source": "internal leaf access (processed_data store)"
        }
      ],
      "outputs": [
        {
          "name": "validation_result",
          "type": "dict",
          "description": "JSON with valid_count (int), invalid_count (int), errors (list)",
          "consumer": "parent"
        }
      ],
      "signature": "def ValidateQuality(validation_rules: dict, processed_data: list) -> dict"
    },
    {
      "name": "ExportResults",
      "purpose": "Export only valid records to output destination",
      "behavior": "Read processed_data, filter valid records, write to output destination (e.g., file, API), return export summary",
      "boundary": {
        "in_scope": [
          "filtering valid records",
          "writing to destination"
        ],
        "out_of_scope": [
          "ingestion",
          "transformation",
          "validation"
        ]
      },
      "semantic_inputs": [
        "export_destination (from parent input)",
        "processed_data (from data store)"
      ],
      "semantic_outputs": [
        "export_result (records_exported, errors)"
      ],
      "preconditions": [
        "processed_data has validity flags"
      ],
      "postconditions": [
        "valid records are exported"
      ],
      "guarantees": [
        "logs each step",
        "only exports valid records"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "export_destination",
          "type": "str",
          "description": "Target for export from parent input",
          "source": "parent input"
        },
        {
          "name": "processed_data",
          "type": "list",
          "description": "Transformed records with validity flags from processed_data store",
          "source": "internal leaf access (processed_data store)"
        }
      ],
      "outputs": [
        {
          "name": "export_result",
          "type": "dict",
          "description": "JSON with records_exported (int) and errors (list)",
          "consumer": "parent"
        }
      ],
      "signature": "def ExportResults(export_destination: str, processed_data: list) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "input": "IngestData",
      "transform_config": "TransformData",
      "validation_rules": "ValidateQuality",
      "export_destination": "ExportResults"
    },
    "parent_outputs_produced_by": {
      "output": "ExportResults"
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "IngestData",
      "to_input": "input",
      "note": "parent passes entire input to IngestData"
    },
    {
      "from_node": "parent",
      "from_output": "input.transform_config",
      "to_node": "TransformData",
      "to_input": "transform_config",
      "note": "parent extracts transform config from input"
    },
    {
      "from_node": "parent",
      "from_output": "input.validation_rules",
      "to_node": "ValidateQuality",
      "to_input": "validation_rules",
      "note": "parent extracts validation rules from input"
    },
    {
      "from_node": "parent",
      "from_output": "input.export_destination",
      "to_node": "ExportResults",
      "to_input": "export_destination",
      "note": "parent extracts export destination from input"
    },
    {
      "from_node": "IngestData",
      "from_output": "raw_data (store)",
      "to_node": "TransformData",
      "to_input": "raw_data",
      "note": "IngestData writes to raw_data store, TransformData reads from it"
    },
    {
      "from_node": "TransformData",
      "from_output": "processed_data (store)",
      "to_node": "ValidateQuality",
      "to_input": "processed_data",
      "note": "TransformData writes to processed_data store, ValidateQuality reads from it"
    },
    {
      "from_node": "ValidateQuality",
      "from_output": "processed_data (store, with flags)",
      "to_node": "ExportResults",
      "to_input": "processed_data",
      "note": "ValidateQuality updates processed_data store with validity flags, ExportResults reads from it"
    },
    {
      "from_node": "ExportResults",
      "from_output": "export_result",
      "to_node": "parent",
      "to_input": "output",
      "note": "ExportResults produces the final parent output"
    }
  ]
}
